+        // Evaluate WHERE clause expression against a row of data
+        function evaluateWhereClause(expr, rowData) {
+            if (!expr) return true;
+
+            if (expr.type === 'binary') {
+                const left = evaluateWhereClause(expr.left, rowData);
+                const right = evaluateWhereClause(expr.right, rowData);
+                switch (expr.op) {
+                    case 'AND': return left && right;
+                    case 'OR': return left || right;
+                    case '=': case '==': return left === right;
+                    case '!=': case '<>': return left !== right;
+                    case '<': return left < right;
+                    case '>': return left > right;
+                    case '<=': return left <= right;
+                    case '>=': return left >= right;
+                    default: return true;
+                }
+            } else if (expr.type === 'column') {
+                return rowData[expr.name];
+            } else if (expr.type === 'literal') {
+                return expr.value;
+            } else if (expr.type === 'unary' && expr.op === 'NOT') {
+                return !evaluateWhereClause(expr.operand, rowData);
+            }
+
+            return true;
+        }
